def transfer_funds(conn, from_acc, to_acc, amt):
    try:
        with conn:
            conn.execute('UPDATE accounts SET bal=bal-? WHERE id=?', (amt, from_acc))
            # Simulate failure
            raise RuntimeError('Network drop')
            conn.execute('UPDATE accounts SET bal=bal+? WHERE id=?', (amt, to_acc))
        return True
    except Exception:
        return False
